/**
 * Auto-updater bridge.
 *
 * Tauri 2's `tauri-plugin-updater` does the heavy lifting (signature
 * verification, download, install). We just expose a thin
 * `checkForUpdates()` that the bridge's init function fires on boot,
 * and that the tray's "Check for Updates..." menu item triggers
 * manually.
 *
 * Web mode: no-op. The dashboard hosted in a browser is updated by
 * Vite's normal cache-busted asset URLs (and a service-worker if/when
 * we add one); there is no installable artefact to replace.
 */

import { isTauri } from './index.js';
import { notify } from './notification.js';

export interface CheckOptions {
  /** When true, only show UI if an update is available. Default: false. */
  silentIfNone?: boolean;
}

interface UpdaterModule {
  check(): Promise<UpdateHandle | null>;
}

interface UpdateHandle {
  available: boolean;
  version?: string;
  body?: string;
  downloadAndInstall(progress?: (event: ProgressEvent) => void): Promise<void>;
}

interface ProgressEvent {
  event: 'Started' | 'Progress' | 'Finished';
  data?: { contentLength?: number; chunkLength?: number };
}

/**
 * Check the configured update endpoint. Returns true if an update was
 * applied (caller should restart), false otherwise. Logs and resolves
 * without throwing on transport / config errors.
 */
export async function checkForUpdates(options: CheckOptions = {}): Promise<boolean> {
  if (!isTauri()) return false;

  let mod: UpdaterModule;
  try {
    // The optional Tauri plugins only exist inside a Tauri webview;
    // in a plain browser SPA Vite must not try to pre-bundle them.
    // `/* @vite-ignore */` was insufficient (Vite 5 still resolves
    // string-literal dynamic imports), so we build the specifier at
    // runtime — opaque to Vite's static analyser.
    const updaterModule = ['@tauri-apps', 'plugin-updater'].join('/');
    mod = (await import(/* @vite-ignore */ updaterModule)) as UpdaterModule;
  } catch (err) {
    console.warn('[tauri-bridge] updater plugin not available', err);
    return false;
  }

  let handle: UpdateHandle | null;
  try {
    handle = await mod.check();
  } catch (err) {
    console.warn('[tauri-bridge] update check failed', err);
    return false;
  }

  if (!handle || !handle.available) {
    if (!options.silentIfNone) {
      await notify('SwarmAI Console', 'You are running the latest version.');
    }
    return false;
  }

  await notify(
    'SwarmAI Console — update available',
    `Version ${handle.version ?? 'unknown'} is downloading. The app will restart when ready.`,
  );

  try {
    await handle.downloadAndInstall((event) => {
      // Progress events arrive as { event: "Started" | "Progress" | "Finished" }.
      // We don't render a progress bar today; log for debug.
      console.debug('[tauri-bridge] update progress', event);
    });
    await notify('SwarmAI Console', 'Update installed. Restart to apply.');
    // Trigger graceful restart via the process plugin.
    try {
      // See updater plugin import above — runtime-constructed specifier
      // so Vite's static analyser cannot pre-resolve.
      const processModule = ['@tauri-apps', 'plugin-process'].join('/');
      const proc = (await import(/* @vite-ignore */ processModule)) as { relaunch(): Promise<void> };
      await proc.relaunch();
    } catch (err) {
      console.warn('[tauri-bridge] relaunch failed; user must restart manually', err);
    }
    return true;
  } catch (err) {
    console.warn('[tauri-bridge] update install failed', err);
    await notify('SwarmAI Console', `Update failed: ${(err as Error).message}`);
    return false;
  }
}
