/**
 * Notification bridge — native OS toasts for important events.
 *
 * Used by:
 *   - master-approval queue when a new gated action arrives,
 *   - autonomy / supervisor escalations,
 *   - long-running brief completion (the "your report is ready" ping).
 *
 * In web mode we fall back to the standard `Notification` API. Both
 * paths request permission lazily; callers don't need to gate.
 */

import { isTauri } from './index.js';

export interface NotifyOptions {
  /** Optional URL or anchor the user can click on; web mode only. */
  url?: string;
}

let permissionRequested = false;

async function requestWebPermission(): Promise<NotificationPermission> {
  if (typeof Notification === 'undefined') return 'denied';
  if (Notification.permission === 'granted') return 'granted';
  if (Notification.permission === 'denied') return 'denied';
  if (permissionRequested) return Notification.permission;
  permissionRequested = true;
  try {
    return await Notification.requestPermission();
  } catch {
    return 'denied';
  }
}

/**
 * Fire a notification. Resolves once the OS / browser has accepted
 * the request; never throws.
 */
export async function notify(title: string, body: string, opts: NotifyOptions = {}): Promise<void> {
  if (isTauri()) {
    try {
      const { invoke } = await import('@tauri-apps/api/core');
      await invoke('notify_user', { title, body });
    } catch (err) {
      console.warn('[tauri-bridge] notify failed', err);
    }
    return;
  }

  const permission = await requestWebPermission();
  if (permission !== 'granted') return;
  try {
    const n = new Notification(title, { body });
    if (opts.url) {
      n.onclick = () => {
        window.focus();
        window.location.href = opts.url!;
      };
    }
  } catch (err) {
    console.warn('[tauri-bridge] web notification failed', err);
  }
}
